mapper.update:
UPDATE clazz
name = #{name}, room = #{room}, begin_date = #{beginDate}, end_date = #{endDate}, master_id = #{masterId}, subject = #{subject}, update_time = #{updateTime},
WHERE id = #{id}

mapper.select:
select c.*, e.name master_name, Case when now() > c.end_date then '已结课' when c.begin_date > now() then '未开班' else '在读中' end status from clazz c left join emp e on c.master_id = e.id
and c.name like concat('%',#{name},'%')
and c.end_date >= #{begin}
and c.begin_date <= #{end}
order by c.update_time desc
